document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("romajiToggle");chrome.storage.local.get(["romajiEnabled"],o=>{e.checked=!!o.romajiEnabled}),e.addEventListener("change",()=>{const o=e.checked;chrome.storage.local.set({romajiEnabled:o}),chrome.tabs.query({active:!0,currentWindow:!0},e=>{e[0].url.includes("spotify.com")?(console.log("Sending toggle message to Spotify..."),chrome.tabs.sendMessage(e[0].id,{action:"toggleRomaji",enabled:o})):console.log("Not a Spotify tab! URL is:",e[0].url)})})});